        int predType = Arrays.stream(IntStream.range(0, 9).filter(predType -> Intra4x4PredictionBuilder.lumaPred(predType, hasLeft, hasTop, hasTr, predLeft, predTop, predTopLeft[dInd >> 2], blkX, blkY, pred)))
